// 播放控制条：状态指示 + 停止/重播
import { useStore } from "@/store/useStore";
import { cn } from "@/lib/utils";

interface Props {
  onReplay: () => void;
  onStop: () => void;
}

export default function PlayerBar({ onReplay, onStop }: Props) {
  const status = useStore((s) => s.status);
  const hasResult = useStore((s) => !!s.currentFullText);
  const isPlaying = status === "playing";

  return (
    <div className="flex items-center gap-3 rounded-2xl border border-ink-500/70 bg-ink-700/50 px-4 py-3">
      {/* 状态灯 */}
      <span
        className={cn(
          "h-2.5 w-2.5 shrink-0 rounded-full transition-colors",
          isPlaying ? "animate-pulse-dot bg-neon" : "bg-dark/25"
        )}
      />
      <span className="font-mono text-xs text-dark/60 sm:text-sm">
        {isPlaying ? "🔊 正在朗读配音……" : "就绪 · 等待配音"}
      </span>

      <div className="ml-auto flex gap-2">
        <button
          onClick={onReplay}
          disabled={!hasResult || isPlaying}
          className="rounded-lg bg-amber px-3 py-1.5 text-xs font-bold text-white transition hover:scale-105 disabled:cursor-not-allowed disabled:opacity-30"
        >
          ▶ 重播
        </button>
        <button
          onClick={onStop}
          disabled={!isPlaying}
          className="rounded-lg bg-coral/90 px-3 py-1.5 text-xs font-bold text-white transition hover:scale-105 disabled:cursor-not-allowed disabled:opacity-30"
        >
          ⏹ 停止
        </button>
      </div>
    </div>
  );
}
