// 历史记录区
import { useStore } from "@/store/useStore";
import { STYLE_MAP } from "@/lib/stylePresets";
import { Play, Trash2, X } from "lucide-react";

interface Props {
  onReplay: (id: number) => void;
}

export default function HistoryList({ onReplay }: Props) {
  const history = useStore((s) => s.history);
  const removeHistory = useStore((s) => s.removeHistory);
  const clearHistory = useStore((s) => s.clearHistory);

  return (
    <section className="rounded-2xl border border-ink-500/70 bg-ink-700/40 p-5 sm:p-6">
      <div className="mb-3 flex items-center justify-between">
        <span className="font-mono text-xs text-dark/55">
          📜 配音历史（点击 🔊 重播）
        </span>
        {history.length > 0 && (
          <button
            onClick={clearHistory}
            className="flex items-center gap-1 rounded-md px-2 py-1 text-xs text-dark/45 transition hover:bg-ink-600 hover:text-coral"
          >
            <Trash2 className="h-3 w-3" />
            清空
          </button>
        )}
      </div>

      {history.length === 0 ? (
        <div className="py-6 text-center text-sm text-dark/35">
          还没有配音记录，输入文字试试吧 ~
        </div>
      ) : (
        <ul className="space-y-2">
          {history.map((h) => (
            <li
              key={h.id}
              className="group flex items-center gap-3 rounded-xl border border-transparent bg-ink-800/60 px-3 py-2.5 transition hover:border-ink-500/60 hover:bg-ink-600/40"
            >
              <button
                onClick={() => onReplay(h.id)}
                title="重播"
                className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-neon/15 text-neon transition hover:scale-110 hover:bg-neon/30"
              >
                <Play className="h-3.5 w-3.5 fill-current" />
              </button>
              <span
                className="min-w-0 flex-1 truncate text-sm text-dark/75"
                title={h.text}
              >
                {h.text}
              </span>
              <span className="shrink-0 rounded-full bg-ink-500/60 px-2 py-0.5 font-mono text-[10px] text-amber">
                {STYLE_MAP[h.style].emoji} {h.style}
              </span>
              <span className="hidden shrink-0 font-mono text-[10px] text-dark/30 sm:inline">
                {h.time}
              </span>
              <button
                onClick={() => removeHistory(h.id)}
                title="删除"
                className="shrink-0 rounded-md p-1 text-dark/30 transition hover:text-coral"
              >
                <X className="h-4 w-4" />
              </button>
            </li>
          ))}
        </ul>
      )}
    </section>
  );
}
