// 全局状态：输入参数、播放状态、结果、历史记录
import { create } from "zustand";
import { DEFAULT_STYLE, STYLE_MAP, type StyleKey } from "@/lib/stylePresets";
import type { RewriteResult } from "@/lib/styleLib";

export type PlayStatus = "idle" | "playing";
export type ResultMode = "rewrite" | "direct";

export interface ResultData {
  fullText: string;
  original: string;
  extra: string;
  style: StyleKey;
  mode: ResultMode;
}

export interface HistoryItem {
  id: number;
  text: string; // 用户原文
  style: StyleKey;
  fullText: string; // 实际朗读的文本
  time: string;
}

interface AppState {
  // 输入
  text: string;
  style: StyleKey;
  rate: number;
  pitch: number;
  volume: number; // 0-100
  // 播放
  status: PlayStatus;
  isGenerating: boolean;
  currentFullText: string; // 当前/最近朗读的文本（用于重播）
  // 结果展示
  result: ResultData | null;
  // 历史
  history: HistoryItem[];
  // 录制
  isRecording: boolean;
  // LLM 接入
  apiKey: string;
  useLLM: boolean;
  // Azure TTS 接入
  azureKey: string;
  azureRegion: string;

  // actions
  setText: (t: string) => void;
  setStyle: (s: StyleKey) => void;
  setRate: (v: number) => void;
  setPitch: (v: number) => void;
  setVolume: (v: number) => void;
  resetParams: () => void;
  setStatus: (s: PlayStatus) => void;
  setGenerating: (g: boolean) => void;
  setCurrentFullText: (t: string) => void;
  setResult: (r: ResultData | null) => void;
  applyRewrite: (rw: RewriteResult, style: StyleKey) => void;
  addHistory: (item: Omit<HistoryItem, "id" | "time">) => void;
  removeHistory: (id: number) => void;
  clearHistory: () => void;
  setRecording: (r: boolean) => void;
  setApiKey: (k: string) => void;
  setUseLLM: (u: boolean) => void;
  setAzureKey: (k: string) => void;
  setAzureRegion: (r: string) => void;
}

let historyId = 0;

const defaultPreset = STYLE_MAP[DEFAULT_STYLE];

export const useStore = create<AppState>((set, get) => ({
  text: "",
  style: DEFAULT_STYLE,
  rate: defaultPreset.rate,
  pitch: defaultPreset.pitch,
  volume: 100,
  status: "idle",
  isGenerating: false,
  currentFullText: "",
  result: null,
  history: [],
  isRecording: false,
  apiKey: "",
  useLLM: false,
  azureKey: "",
  azureRegion: "eastus",

  setText: (t) => set({ text: t }),
  setStyle: (s) => {
    // 切换风格时同步默认语速/音调（音量保持用户设置）
    const preset = STYLE_MAP[s];
    set({ style: s, rate: preset.rate, pitch: preset.pitch });
  },
  setRate: (v) => set({ rate: v }),
  setPitch: (v) => set({ pitch: v }),
  setVolume: (v) => set({ volume: v }),
  resetParams: () => {
    const preset = STYLE_MAP[get().style];
    set({ rate: preset.rate, pitch: preset.pitch, volume: 100 });
  },
  setStatus: (s) => set({ status: s }),
  setGenerating: (g) => set({ isGenerating: g }),
  setCurrentFullText: (t) => set({ currentFullText: t }),
  setResult: (r) => set({ result: r }),

  applyRewrite: (rw, style) =>
    set({
      result: {
        fullText: rw.fullText,
        original: rw.original,
        extra: rw.extra,
        style,
        mode: "rewrite",
      },
    }),

  addHistory: (item) =>
    set((state) => ({
      history: [
        { ...item, id: ++historyId, time: new Date().toLocaleTimeString("zh-CN") },
        ...state.history,
      ].slice(0, 10),
    })),

  removeHistory: (id) =>
    set((state) => ({ history: state.history.filter((h) => h.id !== id) })),

  clearHistory: () => set({ history: [] }),
  setRecording: (r) => set({ isRecording: r }),
  setApiKey: (k) => set({ apiKey: k }),
  setUseLLM: (u) => set({ useLLM: u }),
  setAzureKey: (k) => set({ azureKey: k }),
  setAzureRegion: (r) => set({ azureRegion: r }),
}));
