// 录音 hook：用 getDisplayMedia 捕获标签页音频 + MediaRecorder 录制
// 注意：浏览器 TTS 输出不经过 AudioContext，只能通过共享标签页音频的方式捕获

import { useCallback, useRef } from "react";
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";

export function useRecorder() {
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const streamRef = useRef<MediaStream | null>(null);

  const isRecording = useStore((s) => s.isRecording);

  /** 开始录制：请求共享标签页音频 */
  const startRecording = useCallback(async (): Promise<boolean> => {
    try {
      // 优先尝试 tab 音频捕获（更精准）
      let stream: MediaStream;
      try {
        // @ts-ignore - tab capture 优先
        stream = await navigator.mediaDevices.getDisplayMedia({
          video: true,
          audio: true,
        });
      } catch {
        return false;
      }

      // 检查是否有音频轨道
      const audioTracks = stream.getAudioTracks();
      if (audioTracks.length === 0) {
        stream.getTracks().forEach((t) => t.stop());
        return false;
      }

      streamRef.current = stream;
      chunksRef.current = [];

      const mimeType = MediaRecorder.isTypeSupported("audio/webm;codecs=opus")
        ? "audio/webm;codecs=opus"
        : "audio/webm";

      const recorder = new MediaRecorder(
        new MediaStream(audioTracks),
        { mimeType }
      );
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      useStore.getState().setRecording(true);
      return true;
    } catch (e) {
      console.warn("录音启动失败:", e);
      return false;
    }
  }, []);

  /** 停止录制并下载 */
  const stopRecording = useCallback((): Promise<string | null> => {
    return new Promise((resolve) => {
      const recorder = mediaRecorderRef.current;
      if (!recorder) {
        resolve(null);
        return;
      }
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: "audio/webm" });
        const url = URL.createObjectURL(blob);
        // 停止所有轨道
        streamRef.current?.getTracks().forEach((t) => t.stop());
        streamRef.current = null;
        mediaRecorderRef.current = null;
        useStore.getState().setRecording(false);
        resolve(url);
      };
      recorder.stop();
    });
  }, []);

  /** 下载已录制的音频 */
  const downloadRecording = useCallback(
    async (filename?: string) => {
      const url = await stopRecording();
      if (!url) {
        useToast.getState().show("⚠️ 录音失败，请检查是否允许共享音频");
        return;
      }
      const a = document.createElement("a");
      a.href = url;
      a.download = filename || `ai配音_${Date.now()}.webm`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 1000);
      useToast.getState().show("✅ 配音已下载！");
    },
    [stopRecording]
  );

  return { isRecording, startRecording, stopRecording, downloadRecording };
}
