// Azure TTS 设置面板：填入 Key+Region 后启用神经语音 + 情感风格
import { useState } from "react";
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";
import { ChevronDown, Key, AudioWaveform, ExternalLink } from "lucide-react";

// 国内访问延迟较低的常用 region
const REGIONS = [
  { value: "eastasia", label: "东亚 (香港)" },
  { value: "japaneast", label: "日本东部" },
  { value: "koreacentral", label: "韩国中部" },
  { value: "southeastasia", label: "东南亚 (新加坡)" },
  { value: "eastus", label: "美国东部" },
  { value: "eastus2", label: "美国东部 2" },
  { value: "westus2", label: "美国西部 2" },
  { value: "westeurope", label: "西欧" },
];

export default function TtsSettings() {
  const [expanded, setExpanded] = useState(false);
  const azureKey = useStore((s) => s.azureKey);
  const azureRegion = useStore((s) => s.azureRegion);
  const setAzureKey = useStore((s) => s.setAzureKey);
  const setAzureRegion = useStore((s) => s.setAzureRegion);
  const showToast = useToast((s) => s.show);
  const [inputKey, setInputKey] = useState(azureKey);
  const [inputRegion, setInputRegion] = useState(azureRegion);

  const enabled = !!azureKey;

  const handleSave = () => {
    setAzureKey(inputKey.trim());
    setAzureRegion(inputRegion.trim() || "eastus");
    if (inputKey.trim()) {
      showToast("✅ Azure Key 已保存，将使用神经语音 + 情感风格");
    } else {
      showToast("已清空，将回退到浏览器内置语音");
    }
  };

  return (
    <section className="rounded-2xl border border-ink-500/70 bg-ink-800/40 p-4 sm:p-5">
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center justify-between"
      >
        <span className="flex items-center gap-2 font-mono text-sm text-dark/60">
          <AudioWaveform className="h-4 w-4 text-amber" />
          神经语音引擎
          {enabled ? (
            <span className="rounded-full bg-amber/15 px-2 py-0.5 text-[10px] text-amber">
              Azure 神经语音
            </span>
          ) : (
            <span className="rounded-full bg-ink-500/60 px-2 py-0.5 text-[10px] text-dark/50">
              浏览器内置
            </span>
          )}
        </span>
        <ChevronDown
          className={`h-4 w-4 text-dark/40 transition-transform ${
            expanded ? "rotate-180" : ""
          }`}
        />
      </button>

      {expanded && (
        <div className="mt-4 space-y-3 animate-fade-up">
          <p className="text-xs leading-relaxed text-dark/55">
            填入 Azure Speech Key 即可启用微软神经语音（接近真人音质）+
            情感风格（cheerful/affectionate/angry 等）。
            不填则回退浏览器内置语音（机械化）。每月免费 50 万字符。
          </p>

          <div className="flex gap-2">
            <div className="relative flex-1">
              <Key className="absolute left-3 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-dark/30" />
              <input
                type="password"
                value={inputKey}
                onChange={(e) => setInputKey(e.target.value)}
                placeholder="Azure Speech Key"
                className="w-full rounded-lg border border-ink-500/60 bg-white/60 py-2 pl-9 pr-3 text-sm text-dark outline-none transition focus:border-amber/60"
              />
            </div>
          </div>

          <div className="flex items-center gap-2">
            <span className="shrink-0 text-xs text-dark/55">区域</span>
            <select
              value={inputRegion}
              onChange={(e) => setInputRegion(e.target.value)}
              className="flex-1 rounded-lg border border-ink-500/60 bg-white/60 px-3 py-2 text-sm text-dark outline-none transition focus:border-amber/60"
            >
              {REGIONS.map((r) => (
                <option key={r.value} value={r.value}>
                  {r.label}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center justify-between">
            <a
              href="https://learn.microsoft.com/azure/ai-services/speech-service/overview"
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center gap-1 text-xs text-cyan hover:underline"
            >
              <ExternalLink className="h-3 w-3" />
              如何获取 Azure Speech Key？
            </a>
            <button
              onClick={handleSave}
              className="rounded-lg bg-amber px-4 py-2 text-sm font-semibold text-white transition hover:scale-105"
            >
              保存
            </button>
          </div>

          <p className="text-[10px] leading-relaxed text-dark/30">
            ⚠️ Demo 项目：Key 保存在浏览器本地，仅本机使用，不会上传。
            区域需与你在 Azure 创建资源时选择的一致，否则会报 403。
          </p>
        </div>
      )}
    </section>
  );
}
