// 操作按钮区
import { useStore } from "@/store/useStore";
import { Sparkles, Volume2 } from "lucide-react";
import { cn } from "@/lib/utils";

interface Props {
  onGenerate: () => void;
  onDirectSpeak: () => void;
}

export default function ActionBar({ onGenerate, onDirectSpeak }: Props) {
  const isGenerating = useStore((s) => s.isGenerating);

  return (
    <div className="flex flex-col gap-3 sm:flex-row">
      <button
        onClick={onGenerate}
        disabled={isGenerating}
        className={cn(
          "group relative flex flex-1 items-center justify-center gap-2 overflow-hidden rounded-2xl bg-gradient-to-r from-amber via-neon to-coral px-6 py-4 font-bold text-white shadow-neon transition-all duration-300",
          isGenerating
            ? "cursor-wait opacity-70"
            : "hover:-translate-y-0.5 hover:shadow-[0_0_28px_rgba(255,77,157,0.55)]"
        )}
      >
        <Sparkles className={cn("h-5 w-5", isGenerating && "animate-spin")} />
        {isGenerating ? "AI 润色中……" : "AI 润色 + 配音"}
      </button>
      <button
        onClick={onDirectSpeak}
        disabled={isGenerating}
        className="flex items-center justify-center gap-2 rounded-2xl border-2 border-cyan/50 bg-white/60 px-6 py-4 font-bold text-cyan transition-all duration-300 hover:-translate-y-0.5 hover:border-cyan hover:bg-cyan/10 disabled:opacity-50"
      >
        <Volume2 className="h-5 w-5" />
        直接朗读
      </button>
    </div>
  );
}
