// 每个风格预设 3 条示例文本，点击一键填充降低使用门槛

import type { StyleKey } from "./stylePresets";

export const EXAMPLE_TEXTS: Record<StyleKey, string[]> = {
  搞笑: [
    "今天上班又迟到了，老板问我怎么回事，我说闹钟坏了，他说那你怎么知道迟到了",
    "我家猫每天早上五点叫我起床，我以为是它爱我，后来发现它只是想让我给它开罐头",
    "减肥第一天：吃了沙拉。减肥第一天晚上：奖励自己一顿火锅，毕竟今天吃了沙拉",
  ],
  深情: [
    "愿你三冬暖，愿你春不寒，愿你天黑有灯，下雨有伞",
    "这世间所有的相遇，都是久别重逢",
    "我想和你一起，看遍这世间所有的美好",
  ],
  霸气: [
    "我的地盘，听我的",
    "成功不是偶然，是我必然的选择",
    "别问行不行，问就是一定行",
  ],
  方言: [
    "今天天气真好，咱们出去逛逛呗",
    "这顿饭吃得真香，下次还来",
    "老伙计，好久不见，想你了",
  ],
  古风: [
    "山有木兮木有枝，心悦君兮君不知",
    "愿得一心人，白首不相离",
    "执子之手，与子偕老",
  ],
  卡通: [
    "今天也是元气满满的一天，加油呀",
    "我最喜欢和朋友一起玩耍啦",
    "小兔子说，要每天开开心心的哦",
  ],
};

/** 随机取一条示例文本 */
export function getRandomExample(style: StyleKey): string {
  const list = EXAMPLE_TEXTS[style];
  return list[Math.floor(Math.random() * list.length)];
}
