// 波形可视化：播放时 15 根波形条错位跳动
import { useStore } from "@/store/useStore";
import { cn } from "@/lib/utils";

// 15 根条的基础高度（px）
const BAR_HEIGHTS = [24, 40, 56, 32, 48, 28, 44, 36, 52, 30, 46, 34, 50, 38, 42];

export default function Visualizer() {
  const isPlaying = useStore((s) => s.status === "playing");
  const hasResult = useStore((s) => !!s.currentFullText);

  if (!hasResult) return null;

  return (
    <div className="rounded-2xl border border-ink-500/70 bg-ink-700/40 p-5 sm:p-6">
      <div className="mb-2 flex items-center justify-between">
        <span className="font-mono text-xs text-amber">
          {isPlaying ? "🎬 配音播放中" : "🎵 波形预览"}
        </span>
        <span className="font-mono text-[10px] text-dark/30">
          {isPlaying ? "LIVE" : "STANDBY"}
        </span>
      </div>
      <div
        className={cn(
          "flex h-20 items-end justify-center gap-1.5",
          isPlaying && "is-playing"
        )}
      >
        {BAR_HEIGHTS.map((h, i) => (
          <div
            key={i}
            className="wave-bar w-1.5 rounded-full bg-gradient-to-t from-neon via-amber to-coral sm:w-2"
            style={{ height: `${h}px` }}
          />
        ))}
      </div>
    </div>
  );
}
