// Azure 音频播放单例管理
// - 全局只保留一个 Audio 实例，新播放自动停旧的
// - generation 用于异步竞态保护：每次发起合成/停止都递增，
//   合成完成后校验 generation 是否仍是当前值，避免旧请求覆盖新请求

let currentAudio: HTMLAudioElement | null = null;
let generation = 0;

/** 发起合成请求时调用：递增 generation 并返回新值 */
export function nextGeneration(): number {
  return ++generation;
}

/** 当前 generation（合成完成后校验用） */
export function currentGeneration(): number {
  return generation;
}

/** 仅清理当前 Audio 实例，不递增 generation */
function clearAudio() {
  if (!currentAudio) return;
  const a = currentAudio;
  a.onplay = null;
  a.onended = null;
  a.onerror = null;
  a.pause();
  if (a.src.startsWith("blob:")) URL.revokeObjectURL(a.src);
  a.src = "";
  currentAudio = null;
}

/** 停止所有 Azure 播放：递增 generation（令进行中合成失效）+ 清 Audio */
export function stopAllAudio() {
  generation++;
  clearAudio();
}

/** 播放一个 Blob 音频（自动停掉上一个） */
export function playBlob(
  blob: Blob,
  opts: {
    volume?: number;
    onplay?: () => void;
    onended?: () => void;
    onerror?: () => void;
  }
): void {
  clearAudio();
  const url = URL.createObjectURL(blob);
  const audio = new Audio(url);
  if (opts.volume != null) audio.volume = opts.volume;
  currentAudio = audio;
  audio.onplay = () => opts.onplay?.();
  audio.onended = () => {
    if (currentAudio === audio) currentAudio = null;
    URL.revokeObjectURL(url);
    opts.onended?.();
  };
  audio.onerror = () => {
    if (currentAudio === audio) currentAudio = null;
    URL.revokeObjectURL(url);
    opts.onerror?.();
  };
  void audio.play();
}
