// 主页面：组装各模块 + 业务流程编排
import { useCallback, useEffect } from "react";
import Hero from "@/components/Hero";
import TextInput from "@/components/TextInput";
import StyleSelector from "@/components/StyleSelector";
import ParamControls from "@/components/ParamControls";
import LLMSettings from "@/components/LLMSettings";
import TtsSettings from "@/components/TtsSettings";
import ActionBar from "@/components/ActionBar";
import PlayerBar from "@/components/PlayerBar";
import ResultCard from "@/components/ResultCard";
import Visualizer from "@/components/Visualizer";
import HistoryList from "@/components/HistoryList";
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";
import { useSpeech } from "@/hooks/useSpeech";
import { useRecorder } from "@/hooks/useRecorder";
import { rewriteTextSmart } from "@/lib/llm";
import { isSpeechSupported, onVoicesReady } from "@/lib/speech";

export default function Home() {
  const { speak, stop, replay } = useSpeech();
  const { isRecording, startRecording, downloadRecording } = useRecorder();
  const showToast = useToast((s) => s.show);

  // 预加载语音列表
  useEffect(() => {
    const dispose = onVoicesReady(() => {
      /* 触发浏览器预热语音引擎 */
    });
    return dispose;
  }, []);

  const handleGenerate = useCallback(async () => {
    const { text, style, apiKey, setGenerating, applyRewrite, addHistory } =
      useStore.getState();
    if (!text.trim()) {
      showToast("⚠️ 请输入要配音的文字哦~");
      return;
    }
    if (!isSpeechSupported()) {
      showToast("⚠️ 当前浏览器不支持语音合成");
      return;
    }

    setGenerating(true);
    try {
      const rw = await rewriteTextSmart(text.trim(), style, apiKey);
      applyRewrite(rw, style);
      speak(rw.fullText, {
        onEnd: () =>
          addHistory({ text: text.trim(), style, fullText: rw.fullText }),
      });
    } finally {
      setGenerating(false);
    }
  }, [speak, showToast]);

  const handleDirectSpeak = useCallback(() => {
    const { text, style, setResult, addHistory } = useStore.getState();
    if (!text.trim()) {
      showToast("⚠️ 请输入要朗读的文字");
      return;
    }
    if (!isSpeechSupported()) {
      showToast("⚠️ 当前浏览器不支持语音合成");
      return;
    }
    const trimmed = text.trim();
    setResult({
      fullText: trimmed,
      original: trimmed,
      extra: "",
      style,
      mode: "direct",
    });
    speak(trimmed, {
      onEnd: () => addHistory({ text: trimmed, style, fullText: trimmed }),
    });
  }, [speak, showToast]);

  const handleReplay = useCallback(() => {
    const { currentFullText } = useStore.getState();
    if (!currentFullText) {
      showToast("⚠️ 还没有生成过配音");
      return;
    }
    replay();
  }, [replay, showToast]);

  const handleReplayHistory = useCallback(
    (id: number) => {
      const { history, setStyle, setResult } = useStore.getState();
      const item = history.find((h) => h.id === id);
      if (!item) return;
      setStyle(item.style);
      setResult({
        fullText: item.fullText,
        original: item.text,
        extra: "",
        style: item.style,
        mode: "direct",
      });
      speak(item.fullText);
    },
    [speak]
  );

  /** 录制按钮：未录制时启动录制 + 重新朗读；录制中时停止并下载 */
  const handleRecordToggle = useCallback(async () => {
    if (isRecording) {
      await downloadRecording();
      return;
    }
    const { currentFullText } = useStore.getState();
    if (!currentFullText) {
      showToast("⚠️ 请先生成配音");
      return;
    }
    const ok = await startRecording();
    if (!ok) {
      showToast("⚠️ 请允许共享标签页音频（勾选「共享音频」）");
      return;
    }
    showToast("🎙️ 录制已开始，正在重新朗读…");
    // 重新播放一遍配音
    speak(currentFullText);
  }, [isRecording, startRecording, downloadRecording, speak, showToast]);

  return (
    <main className="mx-auto w-full max-w-3xl px-4 pb-20 sm:px-6">
      <Hero />

      <div className="space-y-4">
        <TextInput />
        <StyleSelector />
        <ParamControls />
        <LLMSettings />
        <TtsSettings />
        <ActionBar
          onGenerate={handleGenerate}
          onDirectSpeak={handleDirectSpeak}
        />
        <PlayerBar onReplay={handleReplay} onStop={stop} />
        <ResultCard
          onDownload={handleRecordToggle}
          isRecording={isRecording}
        />
        <Visualizer />
        <HistoryList onReplay={handleReplayHistory} />
      </div>

      <Footer />
    </main>
  );
}

function Footer() {
  return (
    <footer className="mt-12 text-center font-mono text-[11px] text-dark/30">
      <p>AI 趣配音 · 复古磁带 × 霓虹波普 Demo</p>
      <p className="mt-1">
        Powered by React + Web Speech API · 支持本地词库 / DeepSeek LLM 双引擎
      </p>
    </footer>
  );
}
