// 文本输入区 + 示例文本一键填充
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";
import { Eraser, Lightbulb } from "lucide-react";
import { getRandomExample } from "@/lib/exampleTexts";
import { STYLE_MAP } from "@/lib/stylePresets";

const MAX_LEN = 300;

export default function TextInput() {
  const text = useStore((s) => s.text);
  const setText = useStore((s) => s.setText);
  const style = useStore((s) => s.style);
  const showToast = useToast((s) => s.show);

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const v = e.target.value;
    if (v.length <= MAX_LEN) setText(v);
  };

  const handleFillExample = () => {
    const example = getRandomExample(style);
    setText(example);
    showToast(`已填入${STYLE_MAP[style].name}示例`);
  };

  return (
    <section className="rounded-2xl border border-ink-500/70 bg-ink-800/60 p-5 shadow-card backdrop-blur-sm sm:p-6">
      <div className="mb-3 flex items-center justify-between">
        <label className="font-mono text-sm font-semibold text-amber">
          📝 输入你要配音的文字
        </label>
        <div className="flex gap-1">
          <button
            onClick={handleFillExample}
            className="flex items-center gap-1 rounded-md px-2 py-1 text-xs text-dark/50 transition hover:bg-ink-600 hover:text-amber"
          >
            <Lightbulb className="h-3.5 w-3.5" />
            示例
          </button>
          {text.length > 0 && (
            <button
              onClick={() => setText("")}
              className="flex items-center gap-1 rounded-md px-2 py-1 text-xs text-dark/50 transition hover:bg-ink-600 hover:text-coral"
            >
              <Eraser className="h-3.5 w-3.5" />
              清空
            </button>
          )}
        </div>
      </div>
      <textarea
        value={text}
        onChange={handleChange}
        placeholder="比如：欢迎收听今天的节目！我是你们的AI主播，今天给大家带来一段有趣的配音……"
        className="h-28 w-full resize-y rounded-xl border border-ink-500/60 bg-white/60 p-4 text-sm leading-relaxed text-dark outline-none transition focus:border-amber/60 focus:shadow-amber sm:h-32 sm:text-base"
      />
      <div className="mt-2 text-right font-mono text-xs text-dark/40">
        {text.length} / {MAX_LEN}
      </div>
    </section>
  );
}
