// 风格选择区：6 张风格卡片，悬停可试听（双引擎）
import { useRef } from "react";
import { useStore } from "@/store/useStore";
import { STYLE_LIST, type StylePreset } from "@/lib/stylePresets";
import { cn } from "@/lib/utils";
import { synthesizeAzure } from "@/lib/azureTTS";
import {
  nextGeneration,
  currentGeneration,
  stopAllAudio,
  playBlob,
} from "@/lib/audioPlayer";
import {
  isSpeechSupported,
  speak as speechSpeak,
  stopSpeak,
} from "@/lib/speech";

export default function StyleSelector() {
  const current = useStore((s) => s.style);
  const setStyle = useStore((s) => s.setStyle);
  const hoverTimer = useRef<number | null>(null);

  /** 停止悬停预览（不影响后续正式配音） */
  const stopPreview = () => {
    if (hoverTimer.current) {
      clearTimeout(hoverTimer.current);
      hoverTimer.current = null;
    }
    stopAllAudio();
    stopSpeak();
  };

  /** 悬停 500ms 后试听该风格的 demo 文本 */
  const startPreview = (preset: StylePreset) => {
    if (!isSpeechSupported() && !useStore.getState().azureKey) return;
    if (hoverTimer.current) clearTimeout(hoverTimer.current);
    hoverTimer.current = window.setTimeout(async () => {
      const state = useStore.getState();
      // 正在播正式配音时不抢断
      if (state.status === "playing") return;

      if (state.azureKey) {
        // Azure 神经语音预览
        const gen = nextGeneration();
        try {
          const blob = await synthesizeAzure({
            key: state.azureKey,
            region: state.azureRegion,
            text: preset.demoText,
            preset,
          });
          if (gen !== currentGeneration()) return;
          playBlob(blob, { volume: 1 });
        } catch (e) {
          if (gen !== currentGeneration()) return;
          // 预览失败静默回退 Web Speech（不弹 toast，避免悬停频繁打扰）
          if (isSpeechSupported()) {
            speechSpeak({
              text: preset.demoText,
              voiceHint: preset.voiceHint,
              voiceGender: preset.voiceGender,
              rate: preset.rate,
              pitch: preset.pitch,
              volume: 1,
            });
          }
        }
      } else {
        // Web Speech 预览
        if (!isSpeechSupported()) return;
        stopAllAudio();
        speechSpeak({
          text: preset.demoText,
          voiceHint: preset.voiceHint,
          voiceGender: preset.voiceGender,
          rate: preset.rate,
          pitch: preset.pitch,
          volume: 1,
        });
      }
    }, 500);
  };

  return (
    <section>
      <div className="mb-3 font-mono text-sm text-dark/60">
        🎭 选择配音风格
        <span className="ml-2 text-xs text-dark/35">
          （悬停试听 · 不同风格 = 不同声音 + 语速 + 语调）
        </span>
      </div>
      <div className="grid grid-cols-2 gap-3 sm:grid-cols-3">
        {STYLE_LIST.map((s) => (
          <StyleCard
            key={s.key}
            preset={s}
            active={current === s.key}
            onClick={() => {
              stopPreview();
              setStyle(s.key);
            }}
            onMouseEnter={() => startPreview(s)}
            onMouseLeave={stopPreview}
          />
        ))}
      </div>
    </section>
  );
}

function StyleCard({
  preset,
  active,
  onClick,
  onMouseEnter,
  onMouseLeave,
}: {
  preset: StylePreset;
  active: boolean;
  onClick: () => void;
  onMouseEnter: () => void;
  onMouseLeave: () => void;
}) {
  return (
    <button
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      className={cn(
        "group relative flex flex-col items-center rounded-2xl border-2 px-3 py-4 text-center transition-all duration-300",
        active
          ? "border-neon bg-neon/10 shadow-neon"
          : "border-ink-500/60 bg-ink-700/40 hover:-translate-y-0.5 hover:border-tape/50"
      )}
      style={active ? { boxShadow: `0 0 20px ${preset.glow}` } : undefined}
    >
      <span className="text-3xl transition-transform duration-300 group-hover:scale-110">
        {preset.emoji}
      </span>
      <span
        className={cn(
          "mt-1.5 text-sm font-bold",
          active ? "text-dark" : "text-dark/80"
        )}
      >
        {preset.name}
      </span>
      <span className="mt-0.5 font-mono text-[11px] text-dark/40">
        {preset.desc}
      </span>
      {active && (
        <span className="absolute right-2 top-2 h-2 w-2 animate-glow-pulse rounded-full bg-neon" />
      )}
    </button>
  );
}
