// DeepSeek LLM 接入：可选调用真实大模型做文本润色
// 无 API key 时回退到本地词库

import type { StyleKey } from "./stylePresets";
import { rewriteText, type RewriteResult } from "./styleLib";

const STYLE_PROMPTS: Record<StyleKey, string> = {
  搞笑: "把下面这句话改写成搞笑逗比的风格，可以加点网络梗和夸张表达，但要保留原意，控制在60字以内，只输出改写后的文字不要解释",
  深情: "把下面这句话改写成深情温柔的电台主播风格，可以加点意境描写，情感真挚，控制在60字以内，只输出改写后的文字不要解释",
  霸气: "把下面这句话改写成霸气总裁风格，语气强硬有力，简短有力，控制在60字以内，只输出改写后的文字不要解释",
  方言: "把下面这句话改写成带点方言味的口语风格，可以用点方言词汇，接地气，控制在60字以内，只输出改写后的文字不要解释",
  古风: "把下面这句话改写成古风说书风格，用半文半白的语言，有韵味，控制在60字以内，只输出改写后的文字不要解释",
  卡通: "把下面这句话改写成卡通萌音风格，加点点缀词和语气词，可爱活泼，控制在60字以内，只输出改写后的文字不要解释",
};

export interface LLMOptions {
  apiKey: string;
  style: StyleKey;
  text: string;
}

/** 调用 DeepSeek API 做真实润色 */
export async function rewriteWithLLM(opts: LLMOptions): Promise<RewriteResult> {
  const { apiKey, style, text } = opts;
  const prompt = STYLE_PROMPTS[style];

  const res = await fetch("https://api.deepseek.com/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: "deepseek-chat",
      messages: [
        { role: "system", content: "你是一个专业的文案润色助手，擅长把平淡的话改写成各种有趣风格。" },
        { role: "user", content: `${prompt}\n\n原文：${text}` },
      ],
      temperature: 0.9,
      max_tokens: 120,
    }),
  });

  if (!res.ok) {
    const errText = await res.text().catch(() => "");
    throw new Error(`LLM 请求失败 (${res.status}): ${errText.slice(0, 100)}`);
  }

  const data = await res.json();
  const fullText: string = data?.choices?.[0]?.message?.content?.trim() || text;

  return {
    fullText,
    original: text,
    extra: "",
  };
}

/** 统一润色入口：有 API key 用 LLM，否则用本地词库 */
export async function rewriteTextSmart(
  text: string,
  style: StyleKey,
  apiKey?: string
): Promise<RewriteResult> {
  if (apiKey && apiKey.trim()) {
    try {
      return await rewriteWithLLM({ apiKey: apiKey.trim(), style, text });
    } catch (e) {
      // LLM 失败则回退本地词库
      console.warn("LLM 调用失败，回退本地词库:", e);
      return rewriteText(text, style);
    }
  }
  // 模拟异步延迟，保持 UI 一致体验
  await new Promise((r) => setTimeout(r, 600));
  return rewriteText(text, style);
}
