// Toast 浮层
import { useToast } from "@/store/useToast";
import { cn } from "@/lib/utils";

export default function Toaster() {
  const { message, visible } = useToast();
  return (
    <div
      className={cn(
        "pointer-events-none fixed bottom-8 left-1/2 z-50 -translate-x-1/2 rounded-xl bg-neon px-5 py-2.5 text-sm font-semibold text-cream shadow-neon transition-all duration-300",
        visible
          ? "translate-y-0 opacity-100"
          : "translate-y-4 opacity-0"
      )}
    >
      {message}
    </div>
  );
}
