function pickRandom<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

export interface RewriteResult {
  fullText: string;
  original: string;
  extra: string;
}

/** 模拟 AI 润色：用风格化词库模板改写原文 */
export function rewriteText(originalText: string, style: StyleKey): RewriteResult {
  const lib = STYLE_LIB[style];
  const pattern = pickRandom(lib.patterns);
  const extra = pickRandom(lib.modifiers);
  const fullText = pattern.replace("{text}", originalText).replace("{extra}", extra);
  return { fullText, original: originalText, extra };
}
