// 语音合成 hook：双引擎封装
// - 配置了 Azure Key：走 Azure 神经语音（SSML→mp3 Blob→HTMLAudio 播放）
// - 未配置：回退浏览器 Web Speech API
// 对外接口保持 speak/stop/replay + status 不变，UI 层无感切换
import { useCallback } from "react";
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";
import { STYLE_MAP } from "@/lib/stylePresets";
import { synthesizeAzure } from "@/lib/azureTTS";
import {
  nextGeneration,
  currentGeneration,
  stopAllAudio,
  playBlob,
} from "@/lib/audioPlayer";
import {
  isSpeechSupported,
  speak as speechSpeak,
  stopSpeak,
} from "@/lib/speech";

export function useSpeech() {
  const status = useStore((s) => s.status);
  const showToast = useToast((s) => s.show);

  /** Web Speech 引擎播放 */
  const speakWithWebSpeech = useCallback(
    (text: string, onEnd?: () => void) => {
      if (!isSpeechSupported()) return;
      const state = useStore.getState();
      const preset = STYLE_MAP[state.style];
      speechSpeak({
        text,
        voiceHint: preset.voiceHint,
        voiceGender: preset.voiceGender,
        rate: state.rate,
        pitch: state.pitch,
        volume: state.volume / 100,
        onStart: () => useStore.getState().setStatus("playing"),
        onEnd: () => {
          useStore.getState().setStatus("idle");
          onEnd?.();
        },
        onError: () => useStore.getState().setStatus("idle"),
      });
    },
    []
  );

  /** Azure 神经语音引擎播放（失败自动回退 Web Speech） */
  const speakWithAzure = useCallback(
    async (text: string, onEnd?: () => void) => {
      const gen = nextGeneration();
      const state = useStore.getState();
      const preset = STYLE_MAP[state.style];
      try {
        const blob = await synthesizeAzure({
          key: state.azureKey,
          region: state.azureRegion,
          text,
          preset,
        });
        // 合成期间若已被新请求/stop 取代，则丢弃结果
        if (gen !== currentGeneration()) return;
        playBlob(blob, {
          volume: state.volume / 100,
          onplay: () => useStore.getState().setStatus("playing"),
          onended: () => {
            useStore.getState().setStatus("idle");
            onEnd?.();
          },
          onerror: () => useStore.getState().setStatus("idle"),
        });
      } catch (e) {
        if (gen !== currentGeneration()) return;
        console.warn("Azure TTS 失败，回退 Web Speech:", e);
        showToast("⚠️ Azure 合成失败，已回退内置语音");
        speakWithWebSpeech(text, onEnd);
      }
    },
    [showToast, speakWithWebSpeech]
  );

  const speak = useCallback(
    (text: string, opts?: { onEnd?: () => void }) => {
      const state = useStore.getState();
      state.setCurrentFullText(text);
      // 停掉当前所有播放（递增 generation，令进行中合成失效）
      stopAllAudio();
      stopSpeak();

      if (state.azureKey) {
        void speakWithAzure(text, opts?.onEnd);
      } else {
        if (!isSpeechSupported()) return;
        speakWithWebSpeech(text, opts?.onEnd);
      }
    },
    [speakWithAzure, speakWithWebSpeech]
  );

  const stop = useCallback(() => {
    stopAllAudio();
    stopSpeak();
    useStore.getState().setStatus("idle");
  }, []);

  const replay = useCallback(() => {
    const { currentFullText } = useStore.getState();
    if (currentFullText) speak(currentFullText);
  }, [speak]);

  return { status, speak, stop, replay };
}
