// 参数调节区：语速 / 音调 / 音量
import { useStore } from "@/store/useStore";
import { RotateCcw } from "lucide-react";

export default function ParamControls() {
  const rate = useStore((s) => s.rate);
  const pitch = useStore((s) => s.pitch);
  const volume = useStore((s) => s.volume);
  const setRate = useStore((s) => s.setRate);
  const setPitch = useStore((s) => s.setPitch);
  const setVolume = useStore((s) => s.setVolume);
  const resetParams = useStore((s) => s.resetParams);

  return (
    <section className="rounded-2xl border border-ink-500/70 bg-ink-700/40 p-5 sm:p-6">
      <div className="mb-4 flex items-center justify-between">
        <span className="font-mono text-sm text-dark/60">🎛️ 微调参数</span>
        <button
          onClick={resetParams}
          className="flex items-center gap-1 rounded-md px-2 py-1 text-xs text-dark/45 transition hover:bg-ink-600 hover:text-amber"
        >
          <RotateCcw className="h-3 w-3" />
          重置
        </button>
      </div>
      <div className="grid gap-5 sm:grid-cols-3">
        <Slider
          label="语速"
          value={rate}
          min={0.5}
          max={2}
          step={0.1}
          display={`${rate.toFixed(1)}x`}
          onChange={setRate}
        />
        <Slider
          label="音调"
          value={pitch}
          min={0.5}
          max={2}
          step={0.1}
          display={pitch.toFixed(1)}
          onChange={setPitch}
        />
        <Slider
          label="音量"
          value={volume}
          min={10}
          max={100}
          step={5}
          display={`${volume}%`}
          onChange={setVolume}
        />
      </div>
    </section>
  );
}

function Slider({
  label,
  value,
  min,
  max,
  step,
  display,
  onChange,
}: {
  label: string;
  value: number;
  min: number;
  max: number;
  step: number;
  display: string;
  onChange: (v: number) => void;
}) {
  return (
    <div>
      <div className="mb-2 flex items-baseline justify-between">
        <span className="text-xs text-dark/55">{label}</span>
        <span className="font-mono text-sm font-semibold text-amber">
          {display}
        </span>
      </div>
      <input
        type="range"
        value={value}
        min={min}
        max={max}
        step={step}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="w-full"
      />
    </div>
  );
}
