// Web Speech API 封装
import type { VoiceGender } from "./stylePresets";

export function isSpeechSupported(): boolean {
  return typeof window !== "undefined" && "speechSynthesis" in window;
}

/** 获取语音列表（异步兼容） */
export function loadVoices(): SpeechSynthesisVoice[] {
  if (!isSpeechSupported()) return [];
  return window.speechSynthesis.getVoices();
}

/** 等待语音列表加载完成 */
export function onVoicesReady(cb: (voices: SpeechSynthesisVoice[]) => void): () => void {
  if (!isSpeechSupported()) {
    cb([]);
    return () => {};
  }
  const synth = window.speechSynthesis;
  const initial = synth.getVoices();
  if (initial.length > 0) {
    cb(initial);
    return () => {};
  }
  const handler = () => cb(synth.getVoices());
  synth.addEventListener?.("voiceschanged", handler);
  return () => synth.removeEventListener?.("voiceschanged", handler);
}

/** 按 voice.name 判断性别（兼容主流系统/Edge/Mac 的中文 voice 命名） */
function matchGender(name: string, gender: VoiceGender): boolean {
  if (gender === "any") return true;
  const lower = name.toLowerCase();
  if (gender === "male") {
    // 常见中文男声：Kangkang / Yunxi / Yunyang / Yunjian / Liang / Cheng
    return /male|男|kang|yun|liang|cheng/.test(lower);
  }
  // 常见中文女声：Tingting / Huihui / Yaoyao / Xiaoxiao / Xiaoyi / Hanhan
  return /female|女|ting|hui|xiao|yao|mei|han/.test(lower);
}

/** 挑选最合适的中文语音 */
export function getBestVoice(
  voices: SpeechSynthesisVoice[],
  langHint: string,
  gender: VoiceGender = "any"
): SpeechSynthesisVoice | undefined {
  // 1. 优先：目标语言 + 性别
  let best = voices.find(
    (v) => v.lang.startsWith(langHint) && matchGender(v.name, gender)
  );
  // 2. 目标语言任意性别
  if (!best) best = voices.find((v) => v.lang.startsWith(langHint));
  // 3. 中文任意
  if (!best) best = voices.find((v) => v.lang.startsWith("zh"));
  // 4. 全部兜底
  if (!best) best = voices[0];
  return best;
}

export interface SpeakOptions {
  text: string;
  voiceHint: string;
  voiceGender?: VoiceGender;
  rate: number;
  pitch: number;
  volume: number;
  onStart?: () => void;
  onEnd?: () => void;
  onBoundary?: (charIndex: number) => void;
  onError?: (error: string) => void;
}

/** 朗读文本，返回 utterance 实例 */
export function speak(opts: SpeakOptions): SpeechSynthesisUtterance | null {
  if (!isSpeechSupported()) {
    opts.onError?.("not-supported");
    return null;
  }
  const synth = window.speechSynthesis;
  synth.cancel(); // 先打断当前朗读

  const voices = synth.getVoices();
  const voice = getBestVoice(voices, opts.voiceHint, opts.voiceGender ?? "any");

  const utterance = new SpeechSynthesisUtterance(opts.text);
  if (voice) {
    utterance.voice = voice;
    utterance.lang = voice.lang;
  } else {
    utterance.lang = opts.voiceHint;
  }
  utterance.rate = opts.rate;
  utterance.pitch = opts.pitch;
  utterance.volume = opts.volume;

  utterance.onstart = () => opts.onStart?.();
  utterance.onend = () => opts.onEnd?.();
  utterance.onerror = (e: SpeechSynthesisErrorEvent) => {
    // canceled/interrupted 属正常打断，不报错
    if (e.error !== "canceled" && e.error !== "interrupted") {
      opts.onError?.(e.error);
    } else {
      opts.onEnd?.();
    }
  };
  utterance.onboundary = (e: SpeechSynthesisEvent) =>
    opts.onBoundary?.(e.charIndex);

  synth.speak(utterance);
  return utterance;
}

/** 停止朗读 */
export function stopSpeak(): void {
  if (!isSpeechSupported()) return;
  window.speechSynthesis.cancel();
}
