// LLM 设置面板：可选填 DeepSeek API key 启用真实 AI 润色
import { useState } from "react";
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";
import { ChevronDown, Key, Sparkles, ExternalLink } from "lucide-react";

export default function LLMSettings() {
  const [expanded, setExpanded] = useState(false);
  const apiKey = useStore((s) => s.apiKey);
  const useLLM = useStore((s) => s.useLLM);
  const setApiKey = useStore((s) => s.setApiKey);
  const setUseLLM = useStore((s) => s.setUseLLM);
  const showToast = useToast((s) => s.show);
  const [inputKey, setInputKey] = useState(apiKey);

  const handleSave = () => {
    setApiKey(inputKey.trim());
    if (inputKey.trim()) {
      setUseLLM(true);
      showToast("✅ API Key 已保存，将使用真实 AI 润色");
    } else {
      setUseLLM(false);
      showToast("已清空，将使用本地词库润色");
    }
  };

  return (
    <section className="rounded-2xl border border-ink-500/70 bg-ink-800/40 p-4 sm:p-5">
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center justify-between"
      >
        <span className="flex items-center gap-2 font-mono text-sm text-dark/60">
          <Sparkles className="h-4 w-4 text-neon" />
          AI 润色引擎
          {useLLM ? (
            <span className="rounded-full bg-neon/15 px-2 py-0.5 text-[10px] text-neon">
              真实 LLM
            </span>
          ) : (
            <span className="rounded-full bg-ink-500/60 px-2 py-0.5 text-[10px] text-dark/50">
              本地词库
            </span>
          )}
        </span>
        <ChevronDown
          className={`h-4 w-4 text-dark/40 transition-transform ${
            expanded ? "rotate-180" : ""
          }`}
        />
      </button>

      {expanded && (
        <div className="mt-4 space-y-3 animate-fade-up">
          <p className="text-xs leading-relaxed text-dark/55">
            填入 DeepSeek API Key 即可启用真实大模型润色，效果更自然智能。
            不填则使用本地风格词库（开箱即用）。
          </p>
          <div className="flex gap-2">
            <div className="relative flex-1">
              <Key className="absolute left-3 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-dark/30" />
              <input
                type="password"
                value={inputKey}
                onChange={(e) => setInputKey(e.target.value)}
                placeholder="sk-xxxxxxxxxxxx"
                className="w-full rounded-lg border border-ink-500/60 bg-white/60 py-2 pl-9 pr-3 text-sm text-dark outline-none transition focus:border-amber/60"
              />
            </div>
            <button
              onClick={handleSave}
              className="rounded-lg bg-amber px-4 py-2 text-sm font-semibold text-white transition hover:scale-105"
            >
              保存
            </button>
          </div>
          <a
            href="https://platform.deepseek.com/api_keys"
            target="_blank"
            rel="noreferrer"
            className="inline-flex items-center gap-1 text-xs text-cyan hover:underline"
          >
            <ExternalLink className="h-3 w-3" />
            如何获取 DeepSeek API Key？
          </a>
        </div>
      )}
    </section>
  );
}
