// 配音风格预设：每种风格的语音参数 + 展示信息

export type StyleKey = "搞笑" | "深情" | "霸气" | "方言" | "古风" | "卡通";

/** 音色性别偏好（Web Speech 选声用） */
export type VoiceGender = "male" | "female" | "any";

export interface StylePreset {
  key: StyleKey;
  name: string;
  emoji: string;
  desc: string;

  // —— Web Speech（回退引擎）——
  rate: number; // 语速
  pitch: number; // 音调
  voiceHint: string; // 语言偏好（如 zh-CN / zh-HK / zh-TW）
  voiceGender: VoiceGender; // 音色性别偏好

  // —— Azure TTS（主引擎，配置 Key 后启用）——
  azureVoice: string; // Azure 音色 ID，如 zh-CN-XiaoxiaoNeural
  azureStyle?: string; // 情感风格（cheerful/affectionate/angry...），港台音色不填
  azureRate: string; // 语速（百分比，如 "+10%" / "-15%"）
  azurePitch: string; // 音调（如 "+0Hz" / "-5Hz"）

  /** 悬停预览用的固定试听文本 */
  demoText: string;
  /** 卡片主题色（tailwind 文本/边框色名） */
  accent: string;
  /** 卡片辉光色（rgba） */
  glow: string;
}

