// Azure TTS REST 封装：构建 SSML → 调用 Azure → 返回 mp3 Blob
// 文档：https://learn.microsoft.com/azure/ai-services/speech-service/rest-text-to-speech

import type { StylePreset } from "./stylePresets";

export interface AzureConfig {
  key: string;
  region: string; // 如 eastus / southeastasia
}

export interface SynthesizeOptions extends AzureConfig {
  text: string;
  preset: StylePreset;
}

/** 转义 XML 文本中的特殊字符 */
function escapeXml(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

/** 根据风格预设 + 文本构建 SSML */
export function buildSSML(text: string, preset: StylePreset): string {
  const escaped = escapeXml(text);
  const lang = preset.azureVoice.split("-").slice(0, 2).join("-"); // zh-CN / zh-HK / zh-TW
  const hasStyle = !!preset.azureStyle;

  const inner = hasStyle
    ? `<mstts:express-as style="${preset.azureStyle}"><prosody rate="${preset.azureRate}" pitch="${preset.azurePitch}">${escaped}</prosody></mstts:express-as>`
    : `<prosody rate="${preset.azureRate}" pitch="${preset.azurePitch}">${escaped}</prosody>`;

  return `<speak version="1.0" xmlns="http://www.w3.org/2001/10/synthesis" xmlns:mstts="http://www.w3.org/2001/mstts" xml:lang="${lang}"><voice name="${preset.azureVoice}">${inner}</voice></speak>`;
}

/**
 * 调用 Azure TTS REST API 合成语音
 * 成功返回 mp3 Blob，失败抛出带状态码的错误
 */
export async function synthesizeAzure(
  opts: SynthesizeOptions
): Promise<Blob> {
  const { key, region, text, preset } = opts;
  if (!key || !region) {
    throw new Error("missing-config");
  }

  const url = `https://${region}.tts.speech.microsoft.com/cognitiveservices/v1`;
  const ssml = buildSSML(text, preset);

  const res = await fetch(url, {
    method: "POST",
    headers: {
      "Ocp-Apim-Subscription-Key": key,
      "Content-Type": "application/ssml+xml",
      "X-Microsoft-OutputFormat": "audio-24khz-48kbitrate-mono-mp3",
      "User-Agent": "ai-dubbing-demo",
    },
    body: ssml,
  });

  if (!res.ok) {
    const detail = await res.text().catch(() => "");
    // 401 = key 错；403 = region 错/配额；429 = 限流
    throw new Error(`azure-${res.status}:${detail.slice(0, 120)}`);
  }

  return await res.blob();
}
