// Hero 标题区：复古磁带装饰 + 霓虹标题
import { useStore } from "@/store/useStore";

export default function Hero() {
  const isPlaying = useStore((s) => s.status === "playing");

  return (
    <header className="relative overflow-hidden pt-14 pb-8 text-center">
      {/* 背景光晕 */}
      <div className="pointer-events-none absolute inset-0 -z-10">
        <div className="absolute left-1/2 top-0 h-64 w-[42rem] max-w-[90vw] -translate-x-1/2 rounded-full bg-neon/10 blur-3xl" />
        <div className="absolute left-1/4 top-10 h-40 w-40 rounded-full bg-amber/10 blur-3xl" />
      </div>

      {/* 磁带装饰 */}
      <div className="mb-6 flex justify-center">
        <Cassette spinning={isPlaying} />
      </div>

      <h1 className="font-display text-5xl tracking-tight sm:text-6xl">
        <span className="bg-gradient-to-r from-amber via-neon to-coral bg-clip-text text-transparent drop-shadow-[0_0_18px_rgba(255,77,157,0.35)]">
          AI
        </span>
        <span className="ml-3 font-sans font-black text-dark">趣配音</span>
      </h1>
      <p className="mx-auto mt-4 max-w-md text-sm text-dark/60 sm:text-base">
        输入文字，选个风格，AI 真的读给你听 —— 让你的文字开口说话
      </p>

      {/* 风格小标签条 */}
      <div className="mt-5 flex flex-wrap items-center justify-center gap-2 text-xs text-dark/40">
        <span className="font-mono">REC ●</span>
        <span>搞笑</span><span>·</span>
        <span>深情</span><span>·</span>
        <span>霸气</span><span>·</span>
        <span>方言</span><span>·</span>
        <span>古风</span><span>·</span>
        <span>卡通</span>
      </div>
    </header>
  );
}

/** CSS 复古磁带，播放时卷盘旋转 */
function Cassette({ spinning }: { spinning: boolean }) {
  return (
    <div className="relative flex h-20 w-44 items-center justify-center rounded-xl border border-ink-500 bg-ink-700/80 px-4 shadow-card sm:h-24 sm:w-52">
      {/* 顶部标签纸 */}
      <div className="absolute -top-3 left-1/2 -translate-x-1/2 rounded-sm bg-amber px-3 py-0.5 font-mono text-[10px] font-bold text-white">
        AI · DUBBING
      </div>
      <div className="flex w-full items-center justify-between">
        <Reel spinning={spinning} />
        <div className="mx-2 h-1 flex-1 rounded-full bg-ink-500" />
        <Reel spinning={spinning} />
      </div>
    </div>
  );
}

function Reel({ spinning }: { spinning: boolean }) {
  return (
    <div
      className={`relative h-12 w-12 rounded-full border-2 border-tape/60 bg-ink-900 sm:h-14 sm:w-14 ${
        spinning ? "animate-spin-slow" : ""
      }`}
    >
      <div className="absolute left-1/2 top-1/2 h-3 w-3 -translate-x-1/2 -translate-y-1/2 rounded-full bg-amber" />
      <div className="absolute left-1/2 top-1/2 h-10 w-1 -translate-x-1/2 -translate-y-1/2 bg-tape/30 sm:h-12" />
      <div className="absolute left-1/2 top-1/2 h-1 w-10 -translate-x-1/2 -translate-y-1/2 bg-tape/30 sm:w-12" />
    </div>
  );
}
