// 结果展示区：润色后文本 + 复制/下载按钮
import { useStore } from "@/store/useStore";
import { useToast } from "@/store/useToast";
import { STYLE_MAP } from "@/lib/stylePresets";
import { Copy, Download, Check } from "lucide-react";
import { useState } from "react";
import type { ResultData } from "@/store/useStore";

interface Props {
  onDownload: () => void;
  isRecording: boolean;
}

export default function ResultCard({ onDownload, isRecording }: Props) {
  const result = useStore((s) => s.result);
  const showToast = useToast((s) => s.show);
  const [copied, setCopied] = useState(false);

  if (!result) return null;

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(result.fullText);
      setCopied(true);
      showToast("✅ 配音文本已复制");
      setTimeout(() => setCopied(false), 2000);
    } catch {
      showToast("⚠️ 复制失败，请手动选择文本");
    }
  };

  return (
    <div className="animate-fade-up rounded-2xl border border-ink-500/70 bg-ink-800/60 p-5 sm:p-6">
      <div className="mb-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="font-mono text-xs text-amber">🎬 配音脚本</span>
          {result.mode === "direct" && (
            <span className="rounded-full bg-ink-500/60 px-2 py-0.5 font-mono text-[10px] text-dark/50">
              原文直读
            </span>
          )}
          {result.mode === "rewrite" && (
            <span className="rounded-full bg-neon/15 px-2 py-0.5 font-mono text-[10px] text-neon">
              AI 润色
            </span>
          )}
        </div>
        <div className="flex gap-1.5">
          <button
            onClick={handleCopy}
            className="flex items-center gap-1 rounded-md bg-ink-700/60 px-2.5 py-1 text-xs text-dark/70 transition hover:bg-ink-600 hover:text-amber"
          >
            {copied ? (
              <Check className="h-3 w-3 text-green-500" />
            ) : (
              <Copy className="h-3 w-3" />
            )}
            {copied ? "已复制" : "复制"}
          </button>
          <button
            onClick={onDownload}
            className={`flex items-center gap-1 rounded-md px-2.5 py-1 text-xs font-semibold transition ${
              isRecording
                ? "bg-coral text-white"
                : "bg-neon/15 text-neon hover:bg-neon/25"
            }`}
          >
            <Download className="h-3 w-3" />
            {isRecording ? "录制中…点击停止" : "录制备份"}
          </button>
        </div>
      </div>

      {/* 高亮文本 */}
      <div className="relative rounded-xl border-l-4 border-neon bg-ink-800/80 p-4 leading-8 text-dark/90">
        {renderHighlighted(result)}
      </div>

      {/* 标签 */}
      <div className="mt-3 flex flex-wrap gap-2">
        <Tag>🎭 {result.style}风格</Tag>
        <Tag>
          📝 原文{result.original.length}字 → 配音{result.fullText.length}字
        </Tag>
        <Tag>🎙️ {STYLE_MAP[result.style].name}</Tag>
      </div>

      {isRecording && (
        <div className="mt-3 flex items-center gap-2 rounded-lg bg-coral/10 px-3 py-2 text-xs text-coral">
          <span className="h-2 w-2 animate-pulse-dot rounded-full bg-coral" />
          正在录制配音音频，朗读结束后点击「录制中…点击停止」即可下载
        </div>
      )}
    </div>
  );
}

function Tag({ children }: { children: React.ReactNode }) {
  return (
    <span className="rounded-full bg-neon/15 px-3 py-1 font-mono text-[11px] text-neon">
      {children}
    </span>
  );
}

/** 把 fullText 中的原文（金色）与情绪词（珊瑚红）高亮渲染 */
function renderHighlighted(result: ResultData): React.ReactNode {
  const { fullText, original, extra, mode } = result;
  if (!original) return fullText;

  // LLM 模式（extra 为空）只高亮整体
  if (mode === "rewrite" && !extra) return fullText;

  // 收集高亮区间
  type Range = { start: number; end: number; kind: "original" | "extra" };
  const ranges: Range[] = [];
  const origIdx = fullText.indexOf(original);
  if (origIdx >= 0)
    ranges.push({ start: origIdx, end: origIdx + original.length, kind: "original" });
  if (extra) {
    const extraIdx = fullText.indexOf(extra);
    if (extraIdx >= 0) {
      const r: Range = { start: extraIdx, end: extraIdx + extra.length, kind: "extra" };
      const overlap = ranges.some(
        (x) => r.start < x.end && r.end > x.start
      );
      if (!overlap) ranges.push(r);
    }
  }
  ranges.sort((a, b) => a.start - b.start);

  if (ranges.length === 0) return fullText;

  const nodes: React.ReactNode[] = [];
  let cursor = 0;
  ranges.forEach((r, i) => {
    if (cursor < r.start) {
      nodes.push(<span key={`t-${i}`}>{fullText.slice(cursor, r.start)}</span>);
    }
    nodes.push(
      <span
        key={`h-${i}`}
        className={
          r.kind === "original"
            ? "font-semibold text-amber"
            : "font-semibold text-coral"
        }
      >
        {fullText.slice(r.start, r.end)}
      </span>
    );
    cursor = r.end;
  });
  if (cursor < fullText.length) {
    nodes.push(<span key="t-end">{fullText.slice(cursor)}</span>);
  }
  return nodes;
}
